import { fromOpenai } from 'instructor';
import { OpenAI } from 'openai';
import { z } from 'zod';

const client = fromOpenai(new OpenAI({ apiKey: process.env.OPENAI_API_KEY }));

const IntentSchema = z.object({
  intent: z.enum(['query', 'greeting', 'help', 'goodbye']),
  entities: z.array(z.string()),
  confidence: z.number().min(0).max(1)
});

const response = await client.chat.completions.create({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: "Book a flight" }],
  schema: IntentSchema
});
console.log(response.intent);  // 'query'

